def verify_age(age):
    """
    Belirtilen yaşın yaş doğrulama kriterini karşılayıp karşılamadığını kontrol eder.
    Varsayılan olarak 18 yaş ve üzerini geçerli kabul eder.
    """
    if not isinstance(age, (int, float)):
        raise TypeError("Yaş bir sayı olmalıdır.")
    if age < 0:
        raise ValueError("Yaş negatif olamaz.")
    return age >= 18
